INSERT INTO `information` VALUES (1897,10,160,'INFO_PHOTO',1,1,'Le Restaurant ','Bienvenue dans votre restaurant','INFO_RESTAURANT.jpg',NULL,NULL,1895,1),(2637,10,160,'INFO_PHOTO',1,1,'Les Horaires','Horaires d\'ouverture','INFO_RESERVED.jpg',NULL,NULL,1897,1),(2639,10,160,'INFO_PHOTO',0,0,'Sponsors','Vos fournisseurs sont vos sponsors','INFO_SPONSORS.jpg',NULL,NULL,11292,1),(11292,10,160,'INFO_URL',0,0,'Le Monde ','','','https://www.lemonde.fr','',2639,1),(11299,10,160,'INFO_HTML',1,1,'Adresse',NULL,'',NULL,'<iframe width=\"100%\" height=\"100%\" src=\"https://www.google.com/maps/embed/v1/place?key=AIzaSyBukPBGH0dLpGgN3sQi8RZhCvXyA6CecSA&q=FRANCE\"></iframe>',1896,1),(92322,14752,87231,'INFO_PHOTO',1,1,'Le Restaurant ','<div style=\"text-align: center;\">Emporté, Pain, Traiteur </div>','648d9239092b43.84519010.jpg',NULL,'',1893,1),(92323,14752,87231,'INFO_PHOTO',1,1,'Les Horaires','<div style=\"text-align: center;\">Mercredi midi</div><br/><br /><br /><br /><br/><div style=\"text-align: center;\">jeudi midi et soir</div><br/><br /><br /><br /><br/><div style=\"text-align: center;\">Vendredi midi et soir</div><br/><br /><br /><br /><br/><div style=\"text-align: center;\">Samedi midi et soir</div><br/><br /><br /><br /><br/><div style=\"text-align: center;\">Dimanche midi</div><br/><br /><br /><br /><br/><div style=\"text-align: center;\"><strong>Horaire de service 12h à 13h45 derniére prise de commande fermeture 15h et 19h à 20h45 derniere prise de commande fermeture 23h<br />Tout depacement d\'horaire pourrait engendrer une facturation de personnel.</strong></div><br/><br /><br /><br /><br/><div style=\"text-align: center;\">Etablissement fermé Lundi et Mardi</div>','6488bd471cd443.87161925.jpg',NULL,NULL,2639,1),(92325,14752,88691,'INFO_PHOTO',1,1,'Fournisseurs ','<div style=\"text-align: center;\">La Ferme des Mille ruissseaux à Cresseveuille. <br />(Meline et Antoine)<br /><br /><br /></div><br/><br /><br /><br /><br/><div style=\"text-align: center;\">\"Circuit court\"<br />Boucherie<br />(Patricia)<br /><br /><br />La Ferme de la croix L\'Abbé à Manerbe ( Benoit)<br /><br /><br />Torréfaction du Pays d\'Auge à St Martin de Bienfaite <br />(Pascal)</div><br/><br /><br /><br /><br /><br/><div style=\"text-align: center;\">Poissonnerie Raynaud à Caen</div><br/><br /><br /><br /><br/><div style=\"text-align: center;\"><br /></div><br/><br /><br /><br /><br/><div style=\"text-align: center;\">La Cidrerie Desvoyes à Beaufour Druval<br />(Geraldine et Vincent)<br /><br /></div><br/><br /><br/><div style=\"text-align: center;\"><br /></div><br/><br /><br/><div style=\"text-align: center;\">La Cidrerie Denis Geneviève à Saint Aubin le Bisay<br /><br /><br />Le pain d\'Hélène &amp; Rodolphe<br />Paysans Meuniers Boulangers Bio<br />GAEC La ferme de la boiserie<br />14140 Castillon en auge (5 kms de Livarot)<br /><br /><br />Le Fromage de Chévre, La Ferme de la Biquetiére, 955 route de la Varinière, Tortisambert.<br />14140 Livarot Pays D\'Auge<br />(Gilles)<br /><br /><br />Le Pont l\'êveque, le Pavé d\'Auge et le Montavigny<br />La ferme biologique de Montavigny à Cricqueville en Auge<br /><br />Nos voisins nous font également profiter de leurs jardins !</div>','6488c1718216b1.89342441.jpg',NULL,'',1897,1),(92326,14752,87231,'INFO_URL',1,1,'Le Monde ','','','https://www.lemonde.fr','',93940,1),(92327,14752,87231,'INFO_HTML',1,1,'Adresse','','',NULL,'<iframe width=\"100%\" height=\"100%\" src=\"https://www.google.com/maps/embed/v1/place?key=AIzaSyBukPBGH0dLpGgN3sQi8RZhCvXyA6CecSA&q=La Croisée des Saveurs 198 le bourg 14340  Beaufour druval  France\"></iframe>',11292,1),(92839,14752,88691,'INFO_PHOTO',1,1,'Prévention','<div style=\"text-align: center;\"><br />Il y a un technocrate européen qui, cherchant à justifier son emploi et son salaire, a eu la géniale idée d\'obliger l\'ensemble des restaurateurs à prévenir oralement l\'ensemble de leurs clients des éventuels produits allergènes dangereux que pourraient contenir leurs plats.</div><br/><br /><br /><br /><br /><br /><br/><div style=\"text-align: center;\">C\'est à dire qu\'avant quand quelqu\'un allait au resto en sachant qu\'il avait une allergie ou une intolérance quelconque, cette personne avait l\'intelligence de demander au serveur : « Y a pas d\'huile d\'arachide dans votre machin ? Parce que je suis allergique » et le serveur allait voir le chef, lui posait une question et revenait avec une réponse claire pour le client et le cas échéant lui proposait de manger autre chose...</div><br/><br /><br /><br /><br /><br /><br/><div style=\"text-align: center;\">Il y a un technocrate français qui n\'a pas la moindre idée de ce que c\'est que de travailler dans un restaurant… Il a réussi le pari de surpasser l\'intelligence de son poste de conseillé de l\'Europe en obligeant les restaurateurs français à informer leurs clients par écrit et ceci pour chaque suggestion chaque plat du jour etc etc etc. Donc, parce que je suis un bon citoyen et que je ne vais pas me soustraire à la loi, je tiens par la présente à informer notre aimable clientèle que l\'ensemble de nos plats contient l\'ensemble des cochonneries allergènes du monde ! « Gluten, noix, œuf, poisson, soja, crème, crustacés, mollusques, céleri, moutarde, sésame, lupin, dioxyde de soufre et sulfites... » Alors pour ceux qui ont la trouille, je peux leur donner de très bonnes adresses où toute la nourriture est garantie pasteurisée, javellisée, lyophilisée sans bactéries, sans produits allergènes, sans saveur et sans danger. Et pour les autres …</div><br/><br /><br /><br /><br /><br /><br/><div style=\"text-align: center;\">restez assis et faites-vous simplement plaisir !!</div>','648d9a6471ea54.00138421.jpg',NULL,'',1896,1),(92840,14752,88691,'INFO_PHOTO',1,1,'Nos Menus','<div style=\"text-align: center;\"><span style=\"color: #ffffff;\"><strong>Notre fonctionnement :</strong></span><br />Si vous avez des contraintes d\'horaire, n\'hésitez pas à nous le faire savoir pour que nous puissions nous adapter au mieux. <br /><br />Nous avons la chance de travailler avec des producteurs locaux, ce qui nous garantit une fraîcheur et une qualité de produits. Nous vous proposons un menu varié, avec minimum trois choix d’entrées et de plats à choisir sur notre Ardoise. En conséquence, <br />celle-ci <span style=\"text-decoration: underline;\">change régulièrement en fonction des arrivages.</span></div><br/><br /><br /><br /><br /><br /><br /><br /><br /><br /><br /><br /><br /><br /><br /><br /><br /><br /><br /><br /><br /><br /><br/><div style=\"text-align: center;\"><br /></div>','648d948771b213.16699054.jpg',NULL,'',1894,1),(92841,14752,88691,'INFO_PHOTO',1,1,'Notre Eco Touch’','<div style=\"text-align: center;\">Chez LCDS nous vous proposons une eau de qualité, micro filtrée, bonne pour vous et engagée pour la planète ! <br /><br /></div><br/><br /><br /><br /><br /><br /><br /><br /><br/><div style=\"text-align: center;\">Plate ou pétillante <br /><em>CASTALIE</em><br /><br /></div>','648a0cd69246b9.57547669.jpg',NULL,'',1895,1),(93940,14752,87231,'INFO_VIDEO',1,1,'Traiteur ','<div style=\"text-align: center;\">Plateaux repas <br />Cocktails de reception <br />Carte à emporter <br /><br /><em>Flyers mis à disposition au Bar </em></div>','669bbdb9ea4980.80596695.mp4',NULL,'',2638,1),(107148,14752,88691,'INFO_PHOTO',0,0,'The Fork','\"Nous sommes enthousiastes à l\'idée d\'offrir ce service à nos clients, mais nous nous réservons le droit de ne pas poursuivre avec ceux qui ne partagent pas nos valeurs de respect et de collaboration.\"','',NULL,'',107148,1),(142228,14752,137572,'INFO_PHOTO',0,0,'Menu de la saint Valentin','','697c94f8aa9711.55181108.jpg',NULL,'',142228,1),(134129,21556,129446,'INFO_PHOTO',1,1,'Le Restaurant ','Bienvenue dans votre restaurant','68b5b1ef89bdd5.00286301.jpg',NULL,'',1895,1),(134130,21556,129446,'INFO_PHOTO',1,1,'Les Horaires','Horaires d\'ouverture','INFO_RESERVED.jpg',NULL,'',1897,1),(134132,21556,129446,'INFO_PHOTO',0,0,'Sponsors','Vos fournisseurs sont vos sponsors','INFO_SPONSORS.jpg',NULL,NULL,138937,1),(134133,21556,129446,'INFO_URL',0,0,'Le Monde ','','','https://www.lemonde.fr','',11292,1),(134134,21556,129446,'INFO_HTML',1,1,'Adresse','','',NULL,'<iframe width=\"100%\" height=\"100%\" src=\"https://www.google.com/maps/embed/v1/place?key=AIzaSyBukPBGH0dLpGgN3sQi8RZhCvXyA6CecSA&q=L\'Imprevu Restaurant Lounge 122 Route de la Paoute 06130 Grasse France\"></iframe>',1896,1),(138937,21556,129446,'INFO_VIDEO',1,1,'','','',NULL,'',138944,1),(138944,21556,129446,'INFO_PHOTO',1,1,'','','68b5afbc0ca6d2.19302443.jpg',NULL,'',138945,1),(138945,21556,129446,'INFO_PHOTO',1,1,'','','68b5b1c75a3165.12089536.jpg',NULL,'',138946,1),(138946,21556,129446,'INFO_PHOTO',1,1,'Infos','','68b5b1dcd1d4e9.11928733.jpg',NULL,'',140806,1),(140806,21556,129446,'INFO_PHOTO',1,1,'Origine des viandes','Volaille : France<br />Boeuf : France / Italie <br />Magret canard : Hongrie','',NULL,'',2638,1),(143162,21556,138664,'INFO_PHOTO',1,1,'L\'Imprévu Brunch & Cocktails','','69428218e1c1f0.50306081.jpg',NULL,'',143162,1),(134141,21558,129458,'INFO_PHOTO',1,1,'Le Restaurant ','<strong>Une cuisine du terroir revisitée avec passion</strong><br /><br />Notre cheffe, passionnée par les produits frais et locaux, revisite avec créativité les recettes traditionnelles françaises. Sa carte, élaborée avec soin, propose un large choix de plats savoureux pour tous les goûts ! Laissez-vous tenter par nos ris de veau à la crème, notre parmentier de canard ou encore notre fondant au chocolat maison.','68527b6476ae36.30438290.jpg',NULL,'',1894,1),(134142,21558,129458,'INFO_PHOTO',1,1,'Les Horaires','Déjeuner : de 12h à 14h (sauf mardi,mercredi)<br />Diner : de 19h à 22h00 (sauf mardi, mercredi et dimanche)','INFO_RESERVED.jpg',NULL,'',1896,1),(134144,21558,129458,'INFO_PHOTO',0,0,'Sponsors','Vos fournisseurs sont vos sponsors','INFO_SPONSORS.jpg',NULL,NULL,11292,1),(134145,21558,129458,'INFO_URL',0,0,'Le Monde ','','','https://www.lemonde.fr','',2639,1),(134146,21558,129458,'INFO_HTML',0,0,'Adresse','','',NULL,'<iframe width=\"100%\" height=\"100%\" src=\"https://www.google.com/maps/embed/v1/place?key=AIzaSyBukPBGH0dLpGgN3sQi8RZhCvXyA6CecSA&q=Au Petit Fourneau 31 Rue de l\'Hôpital Auban - Moet 51200 Epernay France\"></iframe>',1897,1),(134313,21558,129458,'INFO_PHOTO',1,1,'La Patate à emporter','N\'oubliez pas le restaurant Au petit fourneau vous propose d\'emporter votre patate !!!!<br />Commandez par téléphone et 30 min après votre commande est prête !!! Possibilité de livraison, nous consulter.','685276f209ba20.36476370.jpg',NULL,'',1895,1);
